const lead = $('When Executed by Parent').item.json;
const nb = $('📡 NeverBounce Check').item ? $('📡 NeverBounce Check').item.json : null;
const mv = $('📡 MillionVerifier Fallback').item ? $('📡 MillionVerifier Fallback').item.json : null;

let status = 'unknown';
let provider = 'none';
let confidence = 0;

if (nb && nb.result) {
  provider = 'neverbounce';
  switch (nb.result) {
    case 'valid': status='valid'; confidence=95; break;
    case 'catchall': status='catchall'; confidence=70; break;
    case 'invalid': status='invalid'; confidence=98; break;
    case 'disposable': status='disposable'; confidence=98; break;
    case 'unknown': status='unknown'; confidence=30; break;
  }
} else if (mv && mv.result) {
  provider = 'millionverifier';
  const r = (mv.result || '').toLowerCase();
  if (r === 'ok' || r === 'good') { status='valid'; confidence=90; }
  else if (r === 'catch_all' || r === 'catchall') { status='catchall'; confidence=65; }
  else if (r === 'bad' || r === 'invalid') { status='invalid'; confidence=95; }
  else if (r === 'disposable') { status='disposable'; confidence=95; }
  else { status='unknown'; confidence=30; }
}

return [{ json: { ...lead, email_status: status, email_verify_provider: provider, email_confidence: confidence } }];
